<?php
declare(strict_types=1);namespace grupo_donato_gestao\Database\Seeds;
class FinanceSeeder{private $db;private int $actor;public function __construct(int $actor=0){$this->db=db_connect();$this->actor=$actor;}public function run():void{$u=model('grupo_donato_gestao\\Models\\Gd_units_model')->get_default();if(!$u||!$this->db->tableExists($this->db->prefixTable('gd_financial_accounts')))return;$t=$this->db->prefixTable('gd_financial_accounts');if($this->db->table($t)->where('unit_id',$u->id)->where('code','MAIN-CASH')->where('deleted',0)->countAllResults())return;$now=gmdate('Y-m-d H:i:s');$this->db->table($t)->insert(['unit_id'=>(int)$u->id,'code'=>'MAIN-CASH','name'=>'Caixa Principal','account_type'=>'cash','status'=>'active','created_at'=>$now,'updated_at'=>$now,'created_by'=>$this->actor?:null,'updated_by'=>$this->actor?:null,'deleted'=>0]);}}
